              "solution": "class Registry:\n    def __init__(self):\n        # key -> field -> (value, created_at, expiry)\n        self._db = {}\n\n    def _live(self, cell, now):\n        if cell is None:\n            return False\n        created_at, expiry = cell[1], cell[2]\n        if expiry is None:\n            return created_at <= now\n        return created_at <= now < expiry\n\n    def set(self, key, field, value):\n        self._db.setdefault(key, {})[field] = (value, 0, None)\n\n    def set_at(self, key, field, value, timestamp, ttl=None):\n        expiry = None if ttl is None else timestamp + ttl\n        self._db.setdefault(key, {})[field] = (value, timestamp, expiry)\n\n    def get_at(self, key, field, timestamp):\n        rec = self._db.get(key)\n        cell = None if rec is None else rec.get(field)\n        if not self._live(cell, timestamp):\n            return None\n        return cell[0]\n\n    def count_live_at(self, key, timestamp):\n        rec = self._db.get(key)\n        if rec is None:\n            return 0\n        return sum(1 for cell in rec.values() if self._live(cell, timestamp))\n",
              "tests": "import unittest\nfrom solution import Registry\n\n\nclass ExerciseTests(unittest.TestCase):\n    def test_untimed_set_visible_at_any_time(self):\n        r = Registry()\n        r.set(\"k\", \"f\", \"v\")\n        self.assertEqual(r.get_at(\"k\", \"f\", 10**9), \"v\")\n\n    def test_set_at_with_ttl_window(self):\n        r = Registry()\n        r.set_at(\"k\", \"f\", \"v\", 10, 5)  # live [10, 15)\n        self.assertIsNone(r.get_at(\"k\", \"f\", 9))\n        self.assertEqual(r.get_at(\"k\", \"f\", 10), \"v\")\n        self.assertEqual(r.get_at(\"k\", \"f\", 14), \"v\")\n        self.assertIsNone(r.get_at(\"k\", \"f\", 15))\n\n    def test_set_at_no_ttl_permanent(self):\n        r = Registry()\n        r.set_at(\"k\", \"f\", \"v\", 100)\n        self.assertEqual(r.get_at(\"k\", \"f\", 100), \"v\")\n        self.assertIsNone(r.get_at(\"k\", \"f\", 99))\n\n    def test_count_live_at(self):\n        r = Registry()\n        r.set_at(\"k\", \"a\", \"1\", 0, 10)   # live [0,10)\n        r.set_at(\"k\", \"b\", \"2\", 0, 100)  # live [0,100)\n        r.set(\"k\", \"c\", \"3\")             # always live\n        self.assertEqual(r.count_live_at(\"k\", 5), 3)\n        self.assertEqual(r.count_live_at(\"k\", 50), 2)   # a expired\n        self.assertEqual(r.count_live_at(\"k\", 1000), 1)  # only c\n\n    def test_count_live_missing_key(self):\n        self.assertEqual(Registry().count_live_at(\"nope\", 0), 0)\n\n    def test_missing_field_is_none(self):\n        r = Registry()\n        r.set(\"k\", \"f\", \"v\")\n        self.assertIsNone(r.get_at(\"k\", \"other\", 0))\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
