                              "solution": "def normalize_host(name):\n    # Trim whitespace and lowercase.\n    key = name.strip().lower()\n    # A trailing dot marks a fully-qualified name; remove exactly one.\n    if key.endswith('.'):\n        key = key[:-1]\n    return key\n",
