                              "type": "exercise",
                              "kind": "applied",
                              "mode": "sync",
                              "prompt": "DNS resolvers never store the whole internet. They normalize a name and ask an authoritative source. Write `resolve(name, lookup)`. `lookup` is an injected function (think: another server's API) that maps a normalized host name to an IP string. Normalize `name` by stripping surrounding whitespace and lowercasing it, then return `lookup(normalized_name)`. Do NOT inspect lookup's internals; only call it.",
                              "solution": "def resolve(name, lookup):\n    # Normalize the key the same way every resolver does: trim + lowercase.\n    key = name.strip().lower()\n    # Query the injected source; we never read its data, we ask it.\n    return lookup(key)\n",
                              "tests": "import unittest\nfrom solution import resolve\n\n\nclass FakeLookup:\n    # Stand-in for 'another file's function'. Candidate must call it, not read it.\n    def __init__(self, table):\n        self._table = table\n    def __call__(self, key):\n        return self._table.get(key)\n\n\nclass TestResolveSingle(unittest.TestCase):\n    def setUp(self):\n        self.lookup = FakeLookup({'example.com': '93.184.216.34',\n                                  'mail.test': '10.0.0.5'})\n\n    def test_plain(self):\n        self.assertEqual(resolve('example.com', self.lookup), '93.184.216.34')\n\n    def test_uppercase_and_spaces(self):\n        self.assertEqual(resolve('  EXAMPLE.COM  ', self.lookup), '93.184.216.34')\n\n    def test_mixed_case(self):\n        self.assertEqual(resolve('Mail.Test', self.lookup), '10.0.0.5')\n\n    def test_missing_returns_none(self):\n        self.assertIsNone(resolve('nope.test', self.lookup))\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
