                              "prompt": "Real resolvers return a sentinel when a name does not resolve. Write `resolve_or(name, lookup, default)`. Normalize `name` (strip + lowercase), call the injected `lookup(key)` which returns an IP string or `None` for unknown hosts. If `lookup` returns `None`, return `default` instead. Otherwise return the IP.",
                              "solution": "def resolve_or(name, lookup, default):\n    key = name.strip().lower()\n    result = lookup(key)\n    # Substitute the caller's sentinel only when the source had no answer.\n    if result is None:\n        return default\n    return result\n",
                              "tests": "import unittest\nfrom solution import resolve_or\n\n\ndef make_lookup(table):\n    def lookup(key):\n        return table.get(key)\n    return lookup\n\n\nclass TestResolveOr(unittest.TestCase):\n    def setUp(self):\n        self.lookup = make_lookup({'a.test': '1.1.1.1'})\n\n    def test_hit(self):\n        self.assertEqual(resolve_or('A.TEST', self.lookup, '0.0.0.0'), '1.1.1.1')\n\n    def test_miss_uses_default(self):\n        self.assertEqual(resolve_or('x.test', self.lookup, '0.0.0.0'), '0.0.0.0')\n\n    def test_strip(self):\n        self.assertEqual(resolve_or('  a.test ', self.lookup, 'NXDOMAIN'), '1.1.1.1')\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
