          "type": "code",
          "run": true,
          "value": "import math\n\n# Float equality trap and the fix:\nprint(0.1 + 0.2 == 0.3)              # False -- IEEE 754 rounding\nprint(math.isclose(0.1 + 0.2, 0.3)) # True  -- use this instead\n\n# floor and ceil\nprint(math.floor(3.9))    # 3\nprint(math.floor(-3.1))   # -4  -- toward -infinity, NOT toward zero\nprint(math.ceil(3.1))     # 4\nprint(math.ceil(-3.9))    # -3\n\n# math.inf\nbest = math.inf\nfor val in [5, 2, 8, 1]:\n    if val < best:\n        best = val\nprint('best:', best)       # 1"
