          "solution": "class Vehicle:\n    def __init__(self, make):\n        self.make = make\n\n    def describe(self):\n        return f\"{self.make} vehicle\"\n\n\nclass Motorcycle(Vehicle):\n    def __init__(self, make, cc):\n        # chain to the parent so self.make is set by Vehicle.__init__\n        super().__init__(make)\n        self.cc = cc\n\n    def describe(self):\n        # override: replace the parent's describe entirely\n        return f\"{self.make} motorcycle ({self.cc}cc)\"\n",
          "tests": "import unittest\nfrom solution import Vehicle, Motorcycle\n\nclass ExerciseTests(unittest.TestCase):\n    def test_base_describe(self):\n        self.assertEqual(Vehicle(\"Ford\").describe(), \"Ford vehicle\")\n\n    def test_subclass_inherits_make_via_super(self):\n        m = Motorcycle(\"Honda\", 600)\n        self.assertEqual(m.make, \"Honda\")\n        self.assertEqual(m.cc, 600)\n\n    def test_subclass_override(self):\n        self.assertEqual(Motorcycle(\"Honda\", 600).describe(), \"Honda motorcycle (600cc)\")\n\n    def test_isinstance_chain(self):\n        m = Motorcycle(\"Yamaha\", 250)\n        self.assertIsInstance(m, Vehicle)\n        self.assertTrue(issubclass(Motorcycle, Vehicle))\n\nif __name__ == '__main__':\n    unittest.main()\n"
