          "type": "exercise",
          "kind": "recall",
          "mode": "sync",
          "prompt": "Use `dataclasses` to write a `Book` dataclass with `order=True` and these fields, in order: `title: str`, `year: int`, `rating: float = 0.0`, and `authors: list` defaulting to an empty list via `field(default_factory=list)` (never `authors: list = []`, which would share one list across all instances).\n\nRely on the auto-generated `__init__`, `__repr__`, `__eq__`, and ordering. Example: `Book('B', 2020) == Book('B', 2020)` is `True`; sorting `[Book('Z', 1), Book('A', 2)]` orders them by `title` first (so `'A'` precedes `'Z'`); and appending to one book's `authors` must not affect another book's `authors` list.",
          "solution": "from dataclasses import dataclass, field\n\n\n@dataclass(order=True)\nclass Book:\n    title: str\n    year: int\n    rating: float = 0.0\n    authors: list = field(default_factory=list)  # mutable default needs field()\n",
          "tests": "import unittest\nfrom solution import Book\n\nclass ExerciseTests(unittest.TestCase):\n    def test_auto_init(self):\n        b = Book('Dune', 1965)\n        self.assertEqual(b.title, 'Dune')\n        self.assertEqual(b.year, 1965)\n        self.assertEqual(b.rating, 0.0)\n        self.assertEqual(b.authors, [])\n\n    def test_auto_repr(self):\n        self.assertIn('Book', repr(Book('Dune', 1965)))\n\n    def test_auto_eq(self):\n        self.assertEqual(Book('B', 2020), Book('B', 2020))\n        self.assertNotEqual(Book('B', 2020), Book('B', 2021))\n\n    def test_order_by_title(self):\n        result = sorted([Book('Z', 1), Book('A', 2)])\n        self.assertEqual([b.title for b in result], ['A', 'Z'])\n\n    def test_mutable_default_isolated(self):\n        b1, b2 = Book('A', 1), Book('B', 2)\n        b1.authors.append('someone')\n        self.assertEqual(b2.authors, [])\n\nif __name__ == '__main__':\n    unittest.main()\n"
