          "type": "exercise",
          "kind": "applied",
          "mode": "sync",
          "prompt": "Write an `Accumulator` class:\n- `__init__(self, initial=0)` — sets `self.total` and `self.call_count = 0`\n- `__call__(self, value)` — adds `value` to `self.total`, increments `self.call_count`, returns `self.total`\n- `reset(self)` — sets `total` and `call_count` back to 0\n- `__repr__` showing total and call count\n\nThe instance must pass `callable(acc)`.",
          "solution": "class Accumulator:\n    \"\"\"A callable object that sums values passed to it.\n\n    __call__ makes an instance usable as a function: acc(5) adds 5 to the running total.\n    \"\"\"\n\n    def __init__(self, initial=0):\n        self.total = initial\n        self.call_count = 0\n\n    def __call__(self, value):\n        self.total += value\n        self.call_count += 1\n        return self.total\n\n    def reset(self):\n        self.total = 0\n        self.call_count = 0\n\n    def __repr__(self):\n        return f\"Accumulator(total={self.total}, calls={self.call_count})\"\n",
          "tests": "import unittest\nfrom solution import Accumulator\n\nclass TestAccumulator(unittest.TestCase):\n    def test_callable(self):\n        acc = Accumulator()\n        self.assertTrue(callable(acc))\n\n    def test_single_call(self):\n        acc = Accumulator()\n        result = acc(10)\n        self.assertEqual(result, 10)\n\n    def test_multiple_calls(self):\n        acc = Accumulator()\n        acc(5)\n        acc(3)\n        self.assertEqual(acc(2), 10)\n\n    def test_initial_value(self):\n        acc = Accumulator(100)\n        self.assertEqual(acc(0), 100)\n        self.assertEqual(acc(50), 150)\n\n    def test_call_count(self):\n        acc = Accumulator()\n        acc(1)\n        acc(2)\n        acc(3)\n        self.assertEqual(acc.call_count, 3)\n\n    def test_total_attribute(self):\n        acc = Accumulator()\n        acc(7)\n        acc(3)\n        self.assertEqual(acc.total, 10)\n\n    def test_reset(self):\n        acc = Accumulator()\n        acc(5)\n        acc(5)\n        acc.reset()\n        self.assertEqual(acc.total, 0)\n        self.assertEqual(acc.call_count, 0)\n\n    def test_pass_as_callback(self):\n        acc = Accumulator()\n        apply = lambda f, v: f(v)\n        apply(acc, 20)\n        apply(acc, 30)\n        self.assertEqual(acc.total, 50)\n\n    def test_repr(self):\n        acc = Accumulator()\n        acc(5)\n        r = repr(acc)\n        self.assertIn(\"Accumulator\", r)\n\nif __name__ == '__main__':\n    unittest.main()\n"
