        {
          "type": "text",
          "value": "### Point and LabeledPoint dataclasses"
        },
        {
          "type": "exercise",
          "kind": "applied",
          "mode": "sync",
          "prompt": "Write two dataclasses:\n\n1. `Point(x: float, y: float)` with `order=True` — add methods `distance_to_origin()` → `sqrt(x²+y²)` and `translate(dx, dy)` → new `Point`.\n2. `LabeledPoint(x: float, y: float, label: str = '', tags: list = ...)` — use `field(default_factory=list)` for tags; in `__post_init__`, if `label` is empty set it to `'(x, y)'`.",
          "solution": "from dataclasses import dataclass, field\n\n\n@dataclass(order=True)\nclass Point:\n    \"\"\"2-D point. order=True generates __lt__, __le__, __gt__, __ge__ automatically.\"\"\"\n    x: float\n    y: float\n\n    def distance_to_origin(self):\n        return (self.x ** 2 + self.y ** 2) ** 0.5\n\n    def translate(self, dx, dy):\n        \"\"\"Return a new Point shifted by (dx, dy).\"\"\"\n        return Point(self.x + dx, self.y + dy)\n\n\n@dataclass\nclass LabeledPoint:\n    \"\"\"Point with an optional label. Fields with defaults must come after fields without.\"\"\"\n    x: float\n    y: float\n    label: str = \"\"\n    tags: list = field(default_factory=list)  # mutable default: use field()\n\n    def __post_init__(self):\n        # Called automatically after __init__; use for derived setup / validation\n        if not self.label:\n            self.label = f\"({self.x}, {self.y})\"\n",
          "tests": "import unittest\nfrom solution import Point, LabeledPoint\n\nclass TestPoint(unittest.TestCase):\n    def test_auto_init(self):\n        p = Point(3.0, 4.0)\n        self.assertEqual(p.x, 3.0)\n        self.assertEqual(p.y, 4.0)\n\n    def test_auto_repr(self):\n        p = Point(1.0, 2.0)\n        self.assertIn(\"Point\", repr(p))\n        self.assertIn(\"1.0\", repr(p))\n\n    def test_auto_eq(self):\n        self.assertEqual(Point(1.0, 2.0), Point(1.0, 2.0))\n        self.assertNotEqual(Point(1.0, 2.0), Point(1.0, 3.0))\n\n    def test_order_lt(self):\n        # order=True: comparison is lexicographic on (x, y)\n        self.assertTrue(Point(1.0, 0.0) < Point(2.0, 0.0))\n        self.assertTrue(Point(1.0, 0.0) < Point(1.0, 1.0))\n\n    def test_sorted(self):\n        pts = [Point(3, 0), Point(1, 5), Point(1, 2)]\n        result = sorted(pts)\n        self.assertEqual(result[0], Point(1, 2))\n\n    def test_distance(self):\n        self.assertAlmostEqual(Point(3.0, 4.0).distance_to_origin(), 5.0)\n\n    def test_translate(self):\n        p = Point(1.0, 2.0).translate(3, -1)\n        self.assertEqual(p, Point(4.0, 1.0))\n\nclass TestLabeledPoint(unittest.TestCase):\n    def test_default_label_via_post_init(self):\n        p = LabeledPoint(1.0, 2.0)\n        self.assertEqual(p.label, \"(1.0, 2.0)\")\n\n    def test_custom_label(self):\n        p = LabeledPoint(0.0, 0.0, label=\"origin\")\n        self.assertEqual(p.label, \"origin\")\n\n    def test_mutable_default_isolated(self):\n        p1 = LabeledPoint(0.0, 0.0)\n        p2 = LabeledPoint(0.0, 0.0)\n        p1.tags.append(\"a\")\n        self.assertEqual(p2.tags, [])  # field(default_factory=list) isolates defaults\n\nif __name__ == '__main__':\n    unittest.main()\n"
        }
