          "solution": "import heapq\n\ndef task_scheduler(tasks):\n    # push (priority, name) tuples; min-heap sorts by priority first, name second\n    h = []\n    for priority, name in tasks:\n        heapq.heappush(h, (priority, name))\n    result = []\n    while h:\n        priority, name = heapq.heappop(h)\n        result.append(name)\n    return result\n\ndef max_heap_largest(nums):\n    # negate all values: smallest negative = largest original\n    h = []\n    for n in nums:\n        heapq.heappush(h, -n)\n    return -heapq.heappop(h)\n",
