          "solution": "import itertools\n\ndef all_combinations(items, r):\n    return list(itertools.combinations(items, r))\n\ndef all_permutations(items, r=None):\n    return list(itertools.permutations(items, r))\n\ndef cartesian_product(a, b):\n    return list(itertools.product(a, b))\n",
          "tests": "import unittest\nfrom solution import all_combinations, all_permutations, cartesian_product\n\nclass TestAllCombinations(unittest.TestCase):\n    def test_c3_2(self):\n        result = all_combinations([1, 2, 3], 2)\n        self.assertEqual(sorted(result), [(1, 2), (1, 3), (2, 3)])\n\n    def test_c4_2_count(self):\n        self.assertEqual(len(all_combinations([1, 2, 3, 4], 2)), 6)\n\n    def test_r_equals_n(self):\n        self.assertEqual(all_combinations([1, 2], 2), [(1, 2)])\n\n    def test_empty(self):\n        self.assertEqual(all_combinations([], 0), [()])\n\nclass TestAllPermutations(unittest.TestCase):\n    def test_p3_full(self):\n        self.assertEqual(len(all_permutations([1, 2, 3])), 6)\n\n    def test_p3_2(self):\n        result = all_permutations([1, 2, 3], 2)\n        self.assertIn((1, 2), result)\n        self.assertIn((2, 1), result)\n        self.assertEqual(len(result), 6)\n\n    def test_p1(self):\n        self.assertEqual(all_permutations([42]), [(42,)])\n\nclass TestCartesianProduct(unittest.TestCase):\n    def test_2x2(self):\n        result = cartesian_product([1, 2], ['a', 'b'])\n        self.assertEqual(result, [(1, 'a'), (1, 'b'), (2, 'a'), (2, 'b')])\n\n    def test_empty_factor(self):\n        self.assertEqual(cartesian_product([1, 2], []), [])\n\n    def test_1x1(self):\n        self.assertEqual(cartesian_product([3], [4]), [(3, 4)])\n\nif __name__ == '__main__':\n    unittest.main()\n"
