          "type": "exercise",
          "kind": "applied",
          "mode": "sync",
          "prompt": "Implement three functions using `functools.partial`:\n\n1. `make_adder(n)` — return a function that adds `n` to its argument. Pre-fill the first argument of `lambda x, y: x + y`.\n\n2. `make_multiplier(n)` — return a function that multiplies its argument by `n`. Same pattern.\n\n3. `apply_twice(f, x)` — apply `f` to `x`, then apply `f` to the result. Return `f(f(x))`.\n\nExamples:\n- `make_adder(5)(3)` → `8`\n- `make_multiplier(2)(5)` → `10`\n- `apply_twice(make_multiplier(2), 3)` → `12`",
          "solution": "import functools\n\ndef make_adder(n):\n    add = lambda x, y: x + y\n    return functools.partial(add, n)   # pre-fill x=n\n\ndef make_multiplier(n):\n    multiply = lambda x, y: x * y\n    return functools.partial(multiply, n)\n\ndef apply_twice(f, x):\n    return f(f(x))\n",
          "tests": "import unittest\nimport functools\nfrom solution import make_adder, make_multiplier, apply_twice\n\nclass TestMakeAdder(unittest.TestCase):\n    def test_add5(self):\n        add5 = make_adder(5)\n        self.assertEqual(add5(3), 8)\n        self.assertEqual(add5(0), 5)\n        self.assertEqual(add5(-5), 0)\n\n    def test_add0(self):\n        add0 = make_adder(0)\n        self.assertEqual(add0(42), 42)\n\nclass TestMakeMultiplier(unittest.TestCase):\n    def test_double(self):\n        double = make_multiplier(2)\n        self.assertEqual(double(5), 10)\n        self.assertEqual(double(0), 0)\n\n    def test_triple(self):\n        triple = make_multiplier(3)\n        self.assertEqual(triple(4), 12)\n\nclass TestApplyTwice(unittest.TestCase):\n    def test_double(self):\n        double = make_multiplier(2)\n        self.assertEqual(apply_twice(double, 3), 12)\n\n    def test_add1(self):\n        inc = make_adder(1)\n        self.assertEqual(apply_twice(inc, 10), 12)\n\n    def test_with_partial_directly(self):\n        add10 = functools.partial(lambda x, y: x + y, 10)\n        self.assertEqual(apply_twice(add10, 5), 25)\n\nif __name__ == '__main__':\n    unittest.main()\n"
