          "solution": "def max_sum_fixed(nums, k):\n    \"\"\"Maximum sum of any contiguous subarray of length k.\"\"\"\n    if k <= 0 or len(nums) < k:\n        return 0\n    # Seed the first window\n    window_sum = sum(nums[:k])\n    best = window_sum\n    # Slide: add incoming element, drop outgoing element\n    for i in range(k, len(nums)):\n        window_sum += nums[i] - nums[i - k]\n        if window_sum > best:\n            best = window_sum\n    return best\n",
          "tests": "import unittest\nfrom solution import max_sum_fixed\n\nclass TestMaxSumFixed(unittest.TestCase):\n    def test_basic(self):\n        self.assertEqual(max_sum_fixed([2, 1, 5, 1, 3, 2], 3), 9)  # [5,1,3]\n    def test_single_window(self):\n        self.assertEqual(max_sum_fixed([1, 2, 3], 3), 6)\n    def test_k_equals_1(self):\n        self.assertEqual(max_sum_fixed([3, 1, 4, 1, 5], 1), 5)\n    def test_negatives(self):\n        self.assertEqual(max_sum_fixed([-1, -2, -3, -4], 2), -3)  # [-1,-2]\n    def test_k_larger_than_array(self):\n        self.assertEqual(max_sum_fixed([1, 2], 5), 0)\n    def test_empty(self):\n        self.assertEqual(max_sum_fixed([], 3), 0)\n    def test_k_zero(self):\n        self.assertEqual(max_sum_fixed([1, 2, 3], 0), 0)\n    def test_all_same(self):\n        self.assertEqual(max_sum_fixed([4, 4, 4, 4], 2), 8)\n\nif __name__ == '__main__':\n    unittest.main()\n"
