          "tests": "import unittest\nfrom solution import build_prefix\n\nclass TestBuildPrefix(unittest.TestCase):\n    def test_basic(self):\n        self.assertEqual(build_prefix([1, 2, 3, 4]), [0, 1, 3, 6, 10])\n\n    def test_single_element(self):\n        self.assertEqual(build_prefix([7]), [0, 7])\n\n    def test_empty(self):\n        self.assertEqual(build_prefix([]), [0])\n\n    def test_negatives(self):\n        self.assertEqual(build_prefix([-1, -2, -3]), [0, -1, -3, -6])\n\n    def test_mixed(self):\n        self.assertEqual(build_prefix([3, -1, 4, -2]), [0, 3, 2, 6, 4])\n\n    def test_zeros(self):\n        self.assertEqual(build_prefix([0, 0, 0]), [0, 0, 0, 0])\n\n    def test_length_is_n_plus_1(self):\n        arr = [1, 2, 3]\n        result = build_prefix(arr)\n        self.assertEqual(len(result), len(arr) + 1)\n\n    def test_first_element_is_zero(self):\n        self.assertEqual(build_prefix([5, 6, 7])[0], 0)\n\n    def test_last_element_is_total(self):\n        arr = [2, 4, 6, 8]\n        result = build_prefix(arr)\n        self.assertEqual(result[-1], sum(arr))\n\nif __name__ == '__main__':\n    unittest.main()\n"
