          "tests": "import unittest\nfrom solution import running_totals\n\nclass TestRunningTotals(unittest.TestCase):\n    def test_basic(self):\n        self.assertEqual(running_totals([1, 2, 3, 4]), [1, 3, 6, 10])\n\n    def test_single(self):\n        self.assertEqual(running_totals([7]), [7])\n\n    def test_empty(self):\n        self.assertEqual(running_totals([]), [])\n\n    def test_negatives(self):\n        self.assertEqual(running_totals([-1, -2, -3]), [-1, -3, -6])\n\n    def test_mixed(self):\n        self.assertEqual(running_totals([5, -3, 2, -4]), [5, 2, 4, 0])\n\n    def test_zeros(self):\n        self.assertEqual(running_totals([0, 0, 0]), [0, 0, 0])\n\n    def test_length_preserved(self):\n        arr = [1, 2, 3, 4, 5]\n        self.assertEqual(len(running_totals(arr)), len(arr))\n\nif __name__ == '__main__':\n    unittest.main()\n"
