          "mode": "sync",
          "prompt": "Implement `largest_rectangle_in_histogram(heights)` (LC 84).\n\nReturn the area of the largest rectangle that can be formed within the histogram.\n\nApproach:\n1. Use a monotonic increasing stack of indices.\n2. When `heights[i] < heights[stack[-1]]`, pop and compute area: height = `heights[popped]`, width = `i` if stack is empty else `i - stack[-1] - 1`.\n3. Append a sentinel `0` to heights so remaining bars are flushed at the end.\n4. Return `0` for empty input.",
          "solution": "def largest_rectangle_in_histogram(heights):\n    \"\"\"LC 84 — Largest Rectangle in Histogram.\n\n    Monotonic increasing stack of indices.  For each bar, while the current\n    bar is shorter than the stack's top, that top bar is 'closed': the\n    rectangle it can extend rightward ends here.  Width = current_index -\n    index_of_the_bar_beneath_the_popped_one - 1.\n    Sentinel 0 appended to force a final flush.\n    \"\"\"\n    stack = []   # indices; heights are non-decreasing from bottom to top\n    max_area = 0\n\n    for i, h in enumerate(heights + [0]):   # sentinel flushes remaining bars\n        while stack and h < heights[stack[-1]]:\n            height = heights[stack.pop()]\n            # width: from the new stack top (+1) to i-1\n            width = i if not stack else i - stack[-1] - 1\n            max_area = max(max_area, height * width)\n        stack.append(i)\n\n    return max_area\n",
          "tests": "import unittest\nfrom solution import largest_rectangle_in_histogram\n\nclass TestLargestRectangle(unittest.TestCase):\n    def test_example1(self):\n        self.assertEqual(largest_rectangle_in_histogram([2,1,5,6,2,3]), 10)\n\n    def test_example2(self):\n        self.assertEqual(largest_rectangle_in_histogram([2,4]), 4)\n\n    def test_all_same(self):\n        self.assertEqual(largest_rectangle_in_histogram([3,3,3,3]), 12)\n\n    def test_single_bar(self):\n        self.assertEqual(largest_rectangle_in_histogram([5]), 5)\n\n    def test_ascending(self):\n        self.assertEqual(largest_rectangle_in_histogram([1,2,3,4,5]), 9)\n\n    def test_descending(self):\n        self.assertEqual(largest_rectangle_in_histogram([5,4,3,2,1]), 9)\n\n    def test_valley(self):\n        # [5, 1, 5] -> best is 1*3=3 or 5*1=5\n        self.assertEqual(largest_rectangle_in_histogram([5,1,5]), 5)\n\n    def test_empty(self):\n        self.assertEqual(largest_rectangle_in_histogram([]), 0)\n\n    def test_single_zero(self):\n        self.assertEqual(largest_rectangle_in_histogram([0]), 0)\n\n    def test_spike(self):\n        # [2, 1, 2] -> best is min 1*3=3 or 2*1=2 -> 3\n        self.assertEqual(largest_rectangle_in_histogram([2,1,2]), 3)\n\nif __name__ == '__main__':\n    unittest.main()\n"
