          "solution": "def is_valid(s):\n    \"\"\"Recall: valid parentheses from memory.\"\"\"\n    match = {')': '(', ']': '[', '}': '{'}\n    stack = []\n    for ch in s:\n        if ch in '([{':\n            stack.append(ch)\n        else:\n            if not stack or stack[-1] != match[ch]:\n                return False\n            stack.pop()\n    return len(stack) == 0\n",
