          "type": "exercise",
          "kind": "recall",
          "mode": "sync",
          "prompt": "**Exercise 1 — BFS level-by-level traversal**\n\nWrite `bfs_levels(graph, start)` that performs BFS on an adjacency-list graph (a `dict` mapping node -> list of neighbors) starting at `start`. Return a list of lists, where each inner list contains the nodes visited at one BFS level, in the order they were dequeued.\n\nReturn `[]` if `start` is not in the graph.\n\nHints:\n- Import and use `collections.deque`.\n- Add `start` to a `visited` set *before* you enqueue it — never after.\n- Capture `len(queue)` at the start of each level loop to know how many nodes belong to the current level.",
          "solution": "from collections import deque\n\ndef bfs_levels(graph, start):\n    \"\"\"Return nodes grouped by BFS level from start.\n    graph: dict mapping node -> list of neighbors\n    Returns a list of lists, one per level.\n    \"\"\"\n    if start not in graph:\n        return []\n    visited = {start}\n    queue = deque([start])\n    levels = []\n    while queue:\n        level_size = len(queue)\n        current_level = []\n        for _ in range(level_size):\n            node = queue.popleft()\n            current_level.append(node)\n            for neighbor in graph[node]:\n                if neighbor not in visited:\n                    visited.add(neighbor)\n                    queue.append(neighbor)\n        levels.append(current_level)\n    return levels\n",
          "tests": "import unittest\nfrom solution import bfs_levels\n\nclass TestBFSLevels(unittest.TestCase):\n    def test_single_node(self):\n        g = {'A': []}\n        self.assertEqual(bfs_levels(g, 'A'), [['A']])\n\n    def test_linear_chain(self):\n        g = {'A': ['B'], 'B': ['C'], 'C': []}\n        result = bfs_levels(g, 'A')\n        self.assertEqual(result, [['A'], ['B'], ['C']])\n\n    def test_two_level_fan(self):\n        g = {'A': ['B', 'C'], 'B': [], 'C': []}\n        result = bfs_levels(g, 'A')\n        self.assertEqual(result[0], ['A'])\n        self.assertCountEqual(result[1], ['B', 'C'])\n\n    def test_three_levels(self):\n        g = {'A': ['B', 'C'], 'B': ['D'], 'C': [], 'D': []}\n        result = bfs_levels(g, 'A')\n        self.assertEqual(len(result), 3)\n        self.assertEqual(result[0], ['A'])\n        self.assertCountEqual(result[1], ['B', 'C'])\n        self.assertEqual(result[2], ['D'])\n\n    def test_start_not_in_graph(self):\n        g = {'A': ['B'], 'B': []}\n        self.assertEqual(bfs_levels(g, 'Z'), [])\n\n    def test_cycle_not_revisited(self):\n        g = {'A': ['B'], 'B': ['A', 'C'], 'C': ['B']}\n        result = bfs_levels(g, 'A')\n        # A -> B -> C; B won't re-add A because visited\n        self.assertEqual(result, [['A'], ['B'], ['C']])\n\nif __name__ == '__main__':\n    unittest.main()\n"
