          "type": "exercise",
          "kind": "recall",
          "mode": "sync",
          "prompt": "**Exercise 2 — Dummy-head deletion**\n\nDefine `class ListNode`, `list_to_nodes`, `nodes_to_list`, and:\n\n`delete_middle(head, val)` — remove the **first** node whose `.val` equals `val` and return the new head. Use a dummy-head so head-deletion needs no special branch.\n\n- If `val` is not in the list, return the list unchanged.\n- If the list is empty (None), return None.",
          "solution": "class ListNode:\n    def __init__(self, val=0, next=None):\n        self.val = val\n        self.next = next\n\n\ndef list_to_nodes(values):\n    if not values:\n        return None\n    head = ListNode(values[0])\n    cur = head\n    for v in values[1:]:\n        cur.next = ListNode(v)\n        cur = cur.next\n    return head\n\n\ndef nodes_to_list(head):\n    result = []\n    cur = head\n    while cur is not None:\n        result.append(cur.val)\n        cur = cur.next\n    return result\n\n\ndef delete_middle(head, val):\n    \"\"\"Remove the first node with the given value using the dummy-head pattern.\"\"\"\n    dummy = ListNode(0)\n    dummy.next = head\n\n    prev = dummy\n    while prev.next is not None:\n        if prev.next.val == val:\n            prev.next = prev.next.next  # splice out\n            break\n        prev = prev.next\n\n    return dummy.next  # real head (unchanged unless head was deleted)\n",
          "tests": "import unittest\nfrom solution import ListNode, list_to_nodes, nodes_to_list, delete_middle\n\n\nclass TestDummyHead(unittest.TestCase):\n    def test_delete_head(self):\n        head = list_to_nodes([1, 2, 3])\n        result = delete_middle(head, 1)\n        self.assertEqual(nodes_to_list(result), [2, 3])\n\n    def test_delete_tail(self):\n        head = list_to_nodes([1, 2, 3])\n        result = delete_middle(head, 3)\n        self.assertEqual(nodes_to_list(result), [1, 2])\n\n    def test_delete_middle_node(self):\n        head = list_to_nodes([1, 2, 3])\n        result = delete_middle(head, 2)\n        self.assertEqual(nodes_to_list(result), [1, 3])\n\n    def test_delete_only_node(self):\n        head = list_to_nodes([5])\n        result = delete_middle(head, 5)\n        self.assertIsNone(result)\n\n    def test_val_not_present(self):\n        head = list_to_nodes([1, 2, 3])\n        result = delete_middle(head, 99)\n        self.assertEqual(nodes_to_list(result), [1, 2, 3])\n\n    def test_empty_list(self):\n        result = delete_middle(None, 1)\n        self.assertIsNone(result)\n\n    def test_delete_first_of_duplicates(self):\n        head = list_to_nodes([2, 2, 3])\n        result = delete_middle(head, 2)\n        self.assertEqual(nodes_to_list(result), [2, 3])\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
