          "solution": "class ListNode:\n    def __init__(self, val=0, next=None):\n        self.val = val\n        self.next = next\n\n\ndef list_to_nodes(values):\n    if not values:\n        return None\n    head = ListNode(values[0])\n    cur = head\n    for v in values[1:]:\n        cur.next = ListNode(v)\n        cur = cur.next\n    return head\n\n\ndef nodes_to_list(head):\n    result = []\n    cur = head\n    while cur is not None:\n        result.append(cur.val)\n        cur = cur.next\n    return result\n\n\ndef merge_two_sorted(l1, l2):\n    \"\"\"LC 21 — Merge two sorted linked lists; return the merged sorted head.\n\n    Use a dummy head so we never need a special case for the first node.\n    Maintain a 'tail' pointer at the end of the result list.\n    \"\"\"\n    dummy = ListNode(0)\n    tail = dummy\n\n    while l1 is not None and l2 is not None:\n        if l1.val <= l2.val:\n            tail.next = l1\n            l1 = l1.next\n        else:\n            tail.next = l2\n            l2 = l2.next\n        tail = tail.next\n\n    tail.next = l1 if l1 is not None else l2\n\n    return dummy.next\n",
          "tests": "import unittest\nfrom solution import ListNode, list_to_nodes, nodes_to_list, merge_two_sorted\n\n\nclass TestMergeTwoSorted(unittest.TestCase):\n    def test_both_empty(self):\n        self.assertIsNone(merge_two_sorted(None, None))\n\n    def test_first_empty(self):\n        l2 = list_to_nodes([1, 2, 3])\n        result = merge_two_sorted(None, l2)\n        self.assertEqual(nodes_to_list(result), [1, 2, 3])\n\n    def test_second_empty(self):\n        l1 = list_to_nodes([1, 2, 3])\n        result = merge_two_sorted(l1, None)\n        self.assertEqual(nodes_to_list(result), [1, 2, 3])\n\n    def test_basic_merge(self):\n        l1 = list_to_nodes([1, 2, 4])\n        l2 = list_to_nodes([1, 3, 4])\n        result = merge_two_sorted(l1, l2)\n        self.assertEqual(nodes_to_list(result), [1, 1, 2, 3, 4, 4])\n\n    def test_single_elements(self):\n        l1 = list_to_nodes([1])\n        l2 = list_to_nodes([2])\n        result = merge_two_sorted(l1, l2)\n        self.assertEqual(nodes_to_list(result), [1, 2])\n\n    def test_single_elements_reversed(self):\n        l1 = list_to_nodes([2])\n        l2 = list_to_nodes([1])\n        result = merge_two_sorted(l1, l2)\n        self.assertEqual(nodes_to_list(result), [1, 2])\n\n    def test_non_overlapping(self):\n        l1 = list_to_nodes([1, 2, 3])\n        l2 = list_to_nodes([4, 5, 6])\n        result = merge_two_sorted(l1, l2)\n        self.assertEqual(nodes_to_list(result), [1, 2, 3, 4, 5, 6])\n\n    def test_all_duplicates(self):\n        l1 = list_to_nodes([1, 1, 1])\n        l2 = list_to_nodes([1, 1])\n        result = merge_two_sorted(l1, l2)\n        self.assertEqual(nodes_to_list(result), [1, 1, 1, 1, 1])\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
