          "solution": "def search_range(nums, target):\n    \"\"\"LC 34 - find first and last position of target in sorted array.\n\n    Two binary searches: one biased left, one biased right.\n    When nums[mid] == target, left search keeps hi = mid-1 to push further left;\n    right search keeps lo = mid+1 to push further right.\n    Returns [-1, -1] if target not present.\n    \"\"\"\n    def find_first(nums, target):\n        lo, hi = 0, len(nums) - 1\n        result = -1\n        while lo <= hi:\n            mid = (lo + hi) // 2\n            if nums[mid] == target:\n                result = mid      # record, but keep searching left\n                hi = mid - 1\n            elif nums[mid] < target:\n                lo = mid + 1\n            else:\n                hi = mid - 1\n        return result\n\n    def find_last(nums, target):\n        lo, hi = 0, len(nums) - 1\n        result = -1\n        while lo <= hi:\n            mid = (lo + hi) // 2\n            if nums[mid] == target:\n                result = mid      # record, but keep searching right\n                lo = mid + 1\n            elif nums[mid] < target:\n                lo = mid + 1\n            else:\n                hi = mid - 1\n        return result\n\n    return [find_first(nums, target), find_last(nums, target)]\n",
          "tests": "import unittest\nfrom solution import search_range\n\n\nclass TestSearchRange(unittest.TestCase):\n\n    def test_basic(self):\n        self.assertEqual(search_range([5, 7, 7, 8, 8, 10], 8), [3, 4])\n\n    def test_not_found(self):\n        self.assertEqual(search_range([5, 7, 7, 8, 8, 10], 6), [-1, -1])\n\n    def test_empty(self):\n        self.assertEqual(search_range([], 0), [-1, -1])\n\n    def test_single_occurrence(self):\n        self.assertEqual(search_range([1, 2, 3], 2), [1, 1])\n\n    def test_all_same_target(self):\n        self.assertEqual(search_range([3, 3, 3, 3], 3), [0, 3])\n\n    def test_target_at_start(self):\n        self.assertEqual(search_range([1, 1, 2, 3], 1), [0, 1])\n\n    def test_target_at_end(self):\n        self.assertEqual(search_range([1, 2, 3, 3], 3), [2, 3])\n\n    def test_single_element_found(self):\n        self.assertEqual(search_range([5], 5), [0, 0])\n\n    def test_single_element_not_found(self):\n        self.assertEqual(search_range([5], 6), [-1, -1])\n\n\nif __name__ == \"__main__\":\n    unittest.main()\n"
