          "prompt": "**Exercise 8 — BST search and insert**\n\nDefine `TreeNode` and implement:\n\n1. `search_bst(root, val)`: return the **node** (not the value) where `node.val == val`, or `None` if not found. Use the BST invariant to skip one subtree at each step.\n\n2. `insert_bst(root, val)`: insert `val` as a new leaf and return the root. If `val` already exists, do nothing. Do not re-balance.",
          "solution": "class TreeNode:\n    def __init__(self, val=0, left=None, right=None):\n        self.val = val\n        self.left = left\n        self.right = right\n\n\ndef search_bst(root, val):\n    \"\"\"Find the node with the given val in a BST — return that subtree root or None.\n\n    BST invariant: left < node < right.\n    At each step, go left if val < node.val, right if val > node.val.\n    \"\"\"\n    if root is None or root.val == val:\n        return root\n    if val < root.val:\n        return search_bst(root.left, val)\n    return search_bst(root.right, val)\n\n\ndef insert_bst(root, val):\n    \"\"\"Insert val into a BST — return the root of the modified tree.\n\n    Standard recursive BST insert: drill down until we find the gap,\n    then attach a new leaf.\n    \"\"\"\n    if root is None:\n        return TreeNode(val)\n    if val < root.val:\n        root.left = insert_bst(root.left, val)\n    elif val > root.val:\n        root.right = insert_bst(root.right, val)\n    # If val == root.val, BST ignores duplicates (no change)\n    return root\n",
          "tests": "import unittest\nfrom solution import TreeNode, search_bst, insert_bst\n\n\ndef inorder(root):\n    \"\"\"Helper: collect BST values inorder (sorted).\"\"\"\n    if root is None:\n        return []\n    return inorder(root.left) + [root.val] + inorder(root.right)\n\n\ndef make_bst():\n    #      4\n    #    /   \\\n    #   2     7\n    #  / \\\n    # 1   3\n    root = TreeNode(4)\n    root.left = TreeNode(2, TreeNode(1), TreeNode(3))\n    root.right = TreeNode(7)\n    return root\n\n\nclass TestSearchBST(unittest.TestCase):\n\n    def test_found_root(self):\n        root = make_bst()\n        self.assertEqual(search_bst(root, 4).val, 4)\n\n    def test_found_left(self):\n        root = make_bst()\n        node = search_bst(root, 2)\n        self.assertEqual(node.val, 2)\n\n    def test_found_leaf(self):\n        root = make_bst()\n        self.assertEqual(search_bst(root, 1).val, 1)\n\n    def test_not_found(self):\n        self.assertIsNone(search_bst(make_bst(), 5))\n\n    def test_empty(self):\n        self.assertIsNone(search_bst(None, 1))\n\n\nclass TestInsertBST(unittest.TestCase):\n\n    def test_insert_into_empty(self):\n        root = insert_bst(None, 5)\n        self.assertEqual(root.val, 5)\n\n    def test_insert_smaller(self):\n        root = make_bst()\n        insert_bst(root, 0)\n        self.assertIn(0, inorder(root))\n\n    def test_insert_larger(self):\n        root = make_bst()\n        insert_bst(root, 9)\n        self.assertIn(9, inorder(root))\n\n    def test_insert_preserves_bst(self):\n        root = make_bst()\n        insert_bst(root, 5)\n        vals = inorder(root)\n        self.assertEqual(vals, sorted(vals))\n\n    def test_insert_duplicate_ignored(self):\n        root = make_bst()\n        before = inorder(root)\n        insert_bst(root, 4)\n        self.assertEqual(inorder(root), before)\n\n\nif __name__ == \"__main__\":\n    unittest.main()\n"
