          "solution": "from collections import defaultdict\n\n\ndef dfs_recursive(graph, start, n):\n    \"\"\"Return sorted list of nodes reachable from start via DFS (recursive).\n\n    Args:\n        graph: adjacency list (defaultdict or dict of lists)\n        start: starting node\n        n: total number of nodes (0..n-1)\n\n    Returns:\n        sorted list of visited node indices\n    \"\"\"\n    visited = set()\n\n    def _dfs(node):\n        visited.add(node)\n        for neighbor in graph[node]:\n            if neighbor not in visited:\n                _dfs(neighbor)\n\n    _dfs(start)\n    return sorted(visited)\n",
          "tests": "import unittest\nfrom collections import defaultdict\nfrom solution import dfs_recursive\n\n\ndef make_graph(n, edges):\n    g = defaultdict(list)\n    for u, v in edges:\n        g[u].append(v)\n        g[v].append(u)\n    return g\n\n\nclass TestDFSRecursive(unittest.TestCase):\n\n    def test_fully_connected(self):\n        g = make_graph(4, [[0, 1], [1, 2], [2, 3]])\n        self.assertEqual(dfs_recursive(g, 0, 4), [0, 1, 2, 3])\n\n    def test_single_node(self):\n        g = make_graph(1, [])\n        self.assertEqual(dfs_recursive(g, 0, 1), [0])\n\n    def test_disconnected_returns_component_only(self):\n        # Nodes 0-1 connected; nodes 2-3 isolated from 0\n        g = make_graph(4, [[0, 1], [2, 3]])\n        result = dfs_recursive(g, 0, 4)\n        self.assertEqual(sorted(result), [0, 1])\n\n    def test_triangle(self):\n        g = make_graph(3, [[0, 1], [1, 2], [0, 2]])\n        result = dfs_recursive(g, 0, 3)\n        self.assertEqual(sorted(result), [0, 1, 2])\n\n    def test_star_graph(self):\n        # 0 connected to 1,2,3,4\n        g = make_graph(5, [[0, 1], [0, 2], [0, 3], [0, 4]])\n        result = dfs_recursive(g, 0, 5)\n        self.assertEqual(sorted(result), [0, 1, 2, 3, 4])\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
