          "value": "from collections import deque\n\nclass Node:\n    def __init__(self, val=0, neighbors=None):\n        self.val = val\n        self.neighbors = neighbors if neighbors is not None else []\n\ndef clone_graph(node):\n    if node is None:\n        return None\n    clones = {}  # original -> clone\n\n    def get_clone(n):\n        if n not in clones:\n            clones[n] = Node(n.val)\n        return clones[n]\n\n    queue = deque([node])\n    get_clone(node)  # seed the starting clone\n\n    while queue:\n        curr = queue.popleft()\n        for neighbor in curr.neighbors:\n            if neighbor not in clones:\n                queue.append(neighbor)\n            get_clone(curr).neighbors.append(get_clone(neighbor))\n\n    return clones[node]\n\n# Build: 1 <-> 2 <-> 3 <-> 4 <-> 1 (cycle)\nn1, n2, n3, n4 = Node(1), Node(2), Node(3), Node(4)\nn1.neighbors = [n2, n4]\nn2.neighbors = [n1, n3]\nn3.neighbors = [n2, n4]\nn4.neighbors = [n3, n1]\n\nclone = clone_graph(n1)\nprint('Clone val:', clone.val)                      # 1\nprint('Clone neighbor vals:', [nb.val for nb in clone.neighbors])  # [2, 4]\nprint('Same object?', clone is n1)                  # False"
