          "type": "code",
          "run": true,
          "value": "from collections import defaultdict\n\ndef has_cycle(n, edges):\n    graph = defaultdict(list)\n    for u, v in edges:\n        graph[u].append(v)  # directed!\n\n    color = [0] * n  # 0=white, 1=gray, 2=black\n\n    def dfs(node):\n        color[node] = 1            # entering: mark gray\n        for neighbor in graph[node]:\n            if color[neighbor] == 1:\n                return True        # back edge to gray node -> cycle!\n            if color[neighbor] == 0:\n                if dfs(neighbor):\n                    return True\n        color[node] = 2            # leaving: mark black\n        return False\n\n    for node in range(n):\n        if color[node] == 0:\n            if dfs(node):\n                return True\n    return False\n\nprint(has_cycle(3, [[0,1],[1,2],[2,0]]))  # True  (0->1->2->0)\nprint(has_cycle(3, [[0,1],[1,2]]))        # False (DAG)"
