          "solution": "from collections import deque\n\n\nclass Node:\n    \"\"\"Node for a graph with a list of neighbors (LC 133 definition).\"\"\"\n    def __init__(self, val=0, neighbors=None):\n        self.val = val\n        self.neighbors = neighbors if neighbors is not None else []\n\n\ndef clone_graph(node):\n    \"\"\"Deep-clone a connected undirected graph (LC 133).\n\n    Uses BFS + a {original: clone} map to handle cycles and shared references.\n\n    Args:\n        node: a Node (or None for empty graph)\n\n    Returns:\n        the clone of the input node\n    \"\"\"\n    if node is None:\n        return None\n\n    clones = {}  # old_node -> new_node\n\n    def get_clone(n):\n        if n not in clones:\n            clones[n] = Node(n.val)\n        return clones[n]\n\n    queue = deque([node])\n    get_clone(node)\n\n    while queue:\n        curr = queue.popleft()\n        for neighbor in curr.neighbors:\n            if neighbor not in clones:\n                queue.append(neighbor)\n            get_clone(curr).neighbors.append(get_clone(neighbor))\n\n    return clones[node]\n",
          "tests": "import unittest\nfrom solution import Node, clone_graph\n\n\ndef build_graph(n, edges):\n    \"\"\"Build graph of n nodes with given undirected edges. Returns node 1.\"\"\"\n    if n == 0:\n        return None\n    nodes = [Node(i) for i in range(1, n + 1)]\n    for u, v in edges:\n        nodes[u - 1].neighbors.append(nodes[v - 1])\n        nodes[v - 1].neighbors.append(nodes[u - 1])\n    return nodes[0]\n\n\ndef collect_vals(node):\n    \"\"\"BFS collect all node vals and neighbor val sets.\"\"\"\n    if node is None:\n        return {}\n    from collections import deque\n    visited = {}\n    queue = deque([node])\n    seen = set()\n    while queue:\n        n = queue.popleft()\n        if id(n) in seen:\n            continue\n        seen.add(id(n))\n        visited[n.val] = sorted(nb.val for nb in n.neighbors)\n        for nb in n.neighbors:\n            queue.append(nb)\n    return visited\n\n\nclass TestCloneGraph(unittest.TestCase):\n\n    def test_none(self):\n        self.assertIsNone(clone_graph(None))\n\n    def test_single_node_no_neighbors(self):\n        node = Node(1)\n        clone = clone_graph(node)\n        self.assertEqual(clone.val, 1)\n        self.assertEqual(clone.neighbors, [])\n        self.assertIsNot(clone, node)\n\n    def test_two_nodes(self):\n        a = Node(1)\n        b = Node(2)\n        a.neighbors.append(b)\n        b.neighbors.append(a)\n        clone = clone_graph(a)\n        self.assertEqual(clone.val, 1)\n        self.assertIsNot(clone, a)\n        self.assertEqual(len(clone.neighbors), 1)\n        self.assertEqual(clone.neighbors[0].val, 2)\n        self.assertIsNot(clone.neighbors[0], b)\n\n    def test_four_node_cycle(self):\n        # 1-2-3-4-1 cycle (LC 133 example)\n        original = build_graph(4, [(1, 2), (2, 3), (3, 4), (4, 1)])\n        clone = clone_graph(original)\n        orig_map = collect_vals(original)\n        clone_map = collect_vals(clone)\n        self.assertEqual(orig_map, clone_map)\n\n    def test_clone_is_deep(self):\n        original = build_graph(3, [(1, 2), (2, 3)])\n        clone = clone_graph(original)\n        # Modify original; clone should be unaffected\n        original.val = 999\n        self.assertEqual(clone.val, 1)\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
