          "solution": "def is_bipartite(graph):\n    \"\"\"Check whether an undirected graph is bipartite (LC 785).\n\n    A graph is bipartite iff it can be 2-colored such that no two adjacent nodes\n    share the same color. Uses BFS coloring.\n\n    Args:\n        graph: adjacency list as list of lists (graph[i] = neighbors of node i)\n\n    Returns:\n        True if bipartite, False otherwise\n    \"\"\"\n    from collections import deque\n    n = len(graph)\n    color = [-1] * n  # -1 = uncolored\n\n    for start in range(n):\n        if color[start] != -1:\n            continue\n        color[start] = 0\n        queue = deque([start])\n        while queue:\n            node = queue.popleft()\n            for neighbor in graph[node]:\n                if color[neighbor] == -1:\n                    color[neighbor] = 1 - color[node]  # flip color\n                    queue.append(neighbor)\n                elif color[neighbor] == color[node]:\n                    return False  # same color -> odd cycle -> not bipartite\n    return True\n",
          "tests": "import unittest\nfrom solution import is_bipartite\n\n\nclass TestIsBipartite(unittest.TestCase):\n\n    def test_even_cycle_bipartite(self):\n        # Square: 0-1-2-3-0 (4-cycle, bipartite)\n        graph = [[1, 3], [0, 2], [1, 3], [2, 0]]\n        self.assertTrue(is_bipartite(graph))\n\n    def test_odd_cycle_not_bipartite(self):\n        # Triangle: 0-1-2-0 (3-cycle, not bipartite)\n        graph = [[1, 2], [0, 2], [0, 1]]\n        self.assertFalse(is_bipartite(graph))\n\n    def test_single_node(self):\n        self.assertTrue(is_bipartite([[]])  )\n\n    def test_two_disconnected_nodes(self):\n        self.assertTrue(is_bipartite([[], []]))\n\n    def test_path_graph(self):\n        # 0-1-2-3 path (always bipartite)\n        graph = [[1], [0, 2], [1, 3], [2]]\n        self.assertTrue(is_bipartite(graph))\n\n    def test_disconnected_one_odd_cycle(self):\n        # Component 1: 0-1 (bipartite); Component 2: 2-3-4-2 (triangle, not bipartite)\n        graph = [[1], [0], [3, 4], [2, 4], [2, 3]]\n        self.assertFalse(is_bipartite(graph))\n\n    def test_complete_bipartite_k33(self):\n        # K3,3: nodes 0,1,2 connected to nodes 3,4,5\n        graph = [\n            [3, 4, 5], [3, 4, 5], [3, 4, 5],\n            [0, 1, 2], [0, 1, 2], [0, 1, 2]\n        ]\n        self.assertTrue(is_bipartite(graph))\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
