          "solution": "class DSU:\n    def __init__(self, n):\n        self.parent = list(range(n))\n        self.rank = [0] * n\n        self.components = n  # start: every node is its own component\n\n    def find(self, x):\n        if self.parent[x] != x:\n            self.parent[x] = self.find(self.parent[x])\n        return self.parent[x]\n\n    def union(self, x, y):\n        rx, ry = self.find(x), self.find(y)\n        if rx == ry:\n            return  # already connected: component count unchanged\n        if self.rank[rx] < self.rank[ry]:\n            self.parent[rx] = ry\n        elif self.rank[rx] > self.rank[ry]:\n            self.parent[ry] = rx\n        else:\n            self.parent[ry] = rx\n            self.rank[rx] += 1\n        self.components -= 1  # two components merged into one\n\n\ndef count_components(n, edges):\n    dsu = DSU(n)\n    for u, v in edges:\n        dsu.union(u, v)\n    return dsu.components\n",
          "tests": "import unittest\nfrom solution import count_components\n\nclass TestCountComponents(unittest.TestCase):\n    def test_no_edges(self):\n        # every node is isolated\n        self.assertEqual(count_components(5, []), 5)\n\n    def test_single_component(self):\n        self.assertEqual(count_components(4, [[0,1],[1,2],[2,3]]), 1)\n\n    def test_two_components(self):\n        self.assertEqual(count_components(5, [[0,1],[1,2],[3,4]]), 2)\n\n    def test_lc_example_1(self):\n        # n=5, edges=[[0,1],[1,2],[3,4]] -> 2\n        self.assertEqual(count_components(5, [[0,1],[1,2],[3,4]]), 2)\n\n    def test_lc_example_2(self):\n        # n=5, edges=[[0,1],[1,2],[2,3],[3,4]] -> 1\n        self.assertEqual(count_components(5, [[0,1],[1,2],[2,3],[3,4]]), 1)\n\n    def test_single_node(self):\n        self.assertEqual(count_components(1, []), 1)\n\n    def test_duplicate_edge_does_not_double_count(self):\n        # edge 0-1 given twice: should still be 1 merge\n        self.assertEqual(count_components(2, [[0,1],[0,1]]), 1)\n\n    def test_all_isolated(self):\n        self.assertEqual(count_components(3, []), 3)\n\nif __name__ == '__main__':\n    unittest.main()\n"
