          "type": "code",
          "run": true,
          "value": "# The template, made concrete — generating all subsets of [1,2,3]\n\ndef subsets(nums):\n    result = []\n\n    def backtrack(start, current):\n        # Record every partial path as a valid subset\n        result.append(list(current))\n\n        for i in range(start, len(nums)):\n            current.append(nums[i])   # CHOOSE\n            backtrack(i + 1, current) # RECURSE (i+1 avoids re-picking)\n            current.pop()             # UN-CHOOSE\n\n    backtrack(0, [])\n    return result\n\nprint(subsets([1, 2, 3]))\n# [[], [1], [1, 2], [1, 2, 3], [1, 3], [2], [2, 3], [3]]"
