          "solution": "def permute_unique(nums):\n    \"\"\"\n    LC 47 - Permutations II.\n    Input may contain duplicates. Return all unique permutations.\n    Sort first, then skip duplicate siblings: if nums[i] == nums[i-1] and\n    used[i-1] is False, we're at the same \"slot\" with a duplicate — skip.\n    \"\"\"\n    nums.sort()\n    result = []\n    used = [False] * len(nums)\n\n    def backtrack(current):\n        if len(current) == len(nums):\n            result.append(list(current))\n            return\n\n        for i in range(len(nums)):\n            if used[i]:\n                continue\n            # Skip duplicate at the same depth level:\n            # nums[i] == nums[i-1] and nums[i-1] was NOT used in this path\n            # means we already explored this value at this position.\n            if i > 0 and nums[i] == nums[i - 1] and not used[i - 1]:\n                continue\n\n            # CHOOSE\n            used[i] = True\n            current.append(nums[i])\n            # RECURSE\n            backtrack(current)\n            # UN-CHOOSE\n            current.pop()\n            used[i] = False\n\n    backtrack([])\n    return result\n",
