          "prompt": "Implement `combination_sum(candidates, target)` — find all unique combinations that sum to `target` (LC 39). Candidates have no duplicates; each may be reused unlimited times. Result order may vary; tests compare as sorted sets.\n\nHints:\n- Sort candidates first.\n- Recurse with `i` (not `i+1`) to allow reuse.\n- `if c > remaining: break` for pruning.",
          "solution": "def combination_sum(candidates, target):\n    \"\"\"\n    LC 39 - Combination Sum.\n    Find all unique combinations that sum to target.\n    Candidates may be reused unlimited times. No duplicates in candidates.\n    Key difference from LC77: we pass the SAME index i (not i+1) to allow reuse.\n    \"\"\"\n    candidates.sort()\n    result = []\n\n    def backtrack(start, current, remaining):\n        if remaining == 0:\n            result.append(list(current))\n            return\n\n        for i in range(start, len(candidates)):\n            c = candidates[i]\n            # Pruning: since candidates are sorted, if c > remaining,\n            # all subsequent candidates are also too large — stop early.\n            if c > remaining:\n                break\n            # CHOOSE\n            current.append(c)\n            # RECURSE: pass i (not i+1) to allow reuse of candidates[i]\n            backtrack(i, current, remaining - c)\n            # UN-CHOOSE\n            current.pop()\n\n    backtrack(0, [], target)\n    return result\n",
          "tests": "import unittest\nfrom solution import combination_sum\n\n\ndef normalize(list_of_lists):\n    return sorted([tuple(sorted(x)) for x in list_of_lists])\n\n\nclass TestCombinationSum(unittest.TestCase):\n    def test_example1(self):\n        result = combination_sum([2, 3, 6, 7], 7)\n        expected = [[2, 2, 3], [7]]\n        self.assertEqual(normalize(result), normalize(expected))\n\n    def test_example2(self):\n        result = combination_sum([2, 3, 5], 8)\n        expected = [[2, 2, 2, 2], [2, 3, 3], [3, 5]]\n        self.assertEqual(normalize(result), normalize(expected))\n\n    def test_no_solution(self):\n        result = combination_sum([3, 5], 7)\n        self.assertEqual(result, [])\n\n    def test_single_candidate_exact(self):\n        result = combination_sum([5], 5)\n        self.assertEqual(normalize(result), normalize([[5]]))\n\n    def test_single_candidate_multiple(self):\n        result = combination_sum([2], 6)\n        self.assertEqual(normalize(result), normalize([[2, 2, 2]]))\n\n    def test_target_zero(self):\n        # Target 0 -> one solution: the empty combination\n        result = combination_sum([1, 2], 0)\n        self.assertEqual(normalize(result), normalize([[]]))\n\n    def test_sums_are_correct(self):\n        target = 10\n        for combo in combination_sum([2, 3, 5, 7], target):\n            self.assertEqual(sum(combo), target)\n\n\nif __name__ == \"__main__\":\n    unittest.main()\n"
