          "solution": "def rob(nums):\n    # LC 198 - House Robber.\n    # State: dp[i] = max money robbing first i houses.\n    # Recurrence: dp[i] = max(dp[i-1], dp[i-2] + nums[i])\n    # Base: dp[0]=nums[0], dp[1]=max(nums[0],nums[1])\n    if not nums:\n        return 0\n    if len(nums) == 1:\n        return nums[0]\n    prev2, prev1 = nums[0], max(nums[0], nums[1])\n    for i in range(2, len(nums)):\n        prev2, prev1 = prev1, max(prev1, prev2 + nums[i])\n    return prev1\n",
          "tests": "import unittest\nfrom solution import rob\n\nclass TestRob(unittest.TestCase):\n    def test_empty(self):\n        self.assertEqual(rob([]), 0)\n\n    def test_single(self):\n        self.assertEqual(rob([5]), 5)\n\n    def test_two(self):\n        self.assertEqual(rob([2, 7]), 7)\n\n    def test_lc_example1(self):\n        # [1,2,3,1] -> rob house 0 and 2 -> 1+3=4\n        self.assertEqual(rob([1, 2, 3, 1]), 4)\n\n    def test_lc_example2(self):\n        # [2,7,9,3,1] -> rob 0,2,4 -> 2+9+1=12\n        self.assertEqual(rob([2, 7, 9, 3, 1]), 12)\n\n    def test_all_same(self):\n        self.assertEqual(rob([5, 5, 5, 5, 5]), 15)\n\n    def test_monotone(self):\n        # [1,2,3,4,5] -> take 1+3+5=9\n        self.assertEqual(rob([1, 2, 3, 4, 5]), 9)\n\nif __name__ == '__main__':\n    unittest.main()\n"
