          "type": "exercise",
          "kind": "recall",
          "mode": "sync",
          "prompt": "Implement `coin_change(coins, amount)` (LC 322).\n\n- Return the **minimum number of coins** to make `amount`, or `-1` if impossible.\n- `dp[0] = 0`, all other cells start at `float('inf')`.\n- For each amount `a` from 1 to `amount`, try every coin `c`; update `dp[a] = min(dp[a], dp[a-c]+1)` when `c <= a`.\n- Coins list is never empty; denominations are positive integers.",
          "solution": "def coin_change(coins, amount):\n    # LC 322 - Coin Change (minimum coins).\n    # State: dp[a] = fewest coins to make amount a.\n    # Recurrence: dp[a] = min(dp[a - c] + 1) for each coin c <= a\n    # Base: dp[0] = 0; dp[a] = infinity initially.\n    if amount == 0:\n        return 0\n    dp = [float('inf')] * (amount + 1)\n    dp[0] = 0\n    for a in range(1, amount + 1):\n        for c in coins:\n            if c <= a and dp[a - c] + 1 < dp[a]:\n                dp[a] = dp[a - c] + 1\n    return dp[amount] if dp[amount] != float('inf') else -1\n",
          "tests": "import unittest\nfrom solution import coin_change\n\nclass TestCoinChange(unittest.TestCase):\n    def test_amount_zero(self):\n        self.assertEqual(coin_change([1, 5, 10], 0), 0)\n\n    def test_lc_example1(self):\n        # coins=[1,2,5], amount=11 -> 3 (5+5+1)\n        self.assertEqual(coin_change([1, 2, 5], 11), 3)\n\n    def test_lc_example2(self):\n        # coins=[2], amount=3 -> -1 (impossible)\n        self.assertEqual(coin_change([2], 3), -1)\n\n    def test_lc_example3(self):\n        self.assertEqual(coin_change([1], 0), 0)\n\n    def test_exact_one_coin(self):\n        self.assertEqual(coin_change([5], 5), 1)\n\n    def test_impossible(self):\n        self.assertEqual(coin_change([3, 7], 2), -1)\n\n    def test_large(self):\n        # coins=[1,5,10,25], amount=100 -> 4 quarters\n        self.assertEqual(coin_change([1, 5, 10, 25], 100), 4)\n\nif __name__ == '__main__':\n    unittest.main()\n"
