          "solution": "def rotate(matrix):\n    \"\"\"\n    LC 48 - Rotate Image.\n    Rotate an n x n matrix 90 degrees clockwise IN PLACE.\n    Two-step trick:\n      1. Transpose (swap matrix[i][j] and matrix[j][i] for j > i).\n      2. Reverse each row.\n    Mutates matrix and also returns it for test convenience.\n    \"\"\"\n    n = len(matrix)\n\n    # Step 1: transpose along the main diagonal\n    for i in range(n):\n        for j in range(i + 1, n):\n            matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]\n\n    # Step 2: reverse each row\n    for row in matrix:\n        row.reverse()\n\n    return matrix\n",
          "tests": "import unittest\nfrom solution import rotate\n\nclass TestRotate(unittest.TestCase):\n    def test_3x3(self):\n        m = [[1,2,3],[4,5,6],[7,8,9]]\n        result = rotate(m)\n        self.assertEqual(result, [[7,4,1],[8,5,2],[9,6,3]])\n\n    def test_4x4(self):\n        m = [[ 5, 1, 9,11],\n             [ 2, 4, 8,10],\n             [13, 3, 6, 7],\n             [15,14,12,16]]\n        result = rotate(m)\n        expected = [[15,13, 2, 5],\n                    [14, 3, 4, 1],\n                    [12, 6, 8, 9],\n                    [16, 7,10,11]]\n        self.assertEqual(result, expected)\n\n    def test_1x1(self):\n        m = [[7]]\n        result = rotate(m)\n        self.assertEqual(result, [[7]])\n\n    def test_2x2(self):\n        m = [[1,2],[3,4]]\n        result = rotate(m)\n        self.assertEqual(result, [[3,1],[4,2]])\n\n    def test_mutates_in_place(self):\n        m = [[1,2],[3,4]]\n        original_id = id(m)\n        rotate(m)\n        self.assertEqual(id(m), original_id)\n        self.assertEqual(m, [[3,1],[4,2]])\n\n    def test_5x5(self):\n        m = [[i*5+j+1 for j in range(5)] for i in range(5)]\n        rotate(m)\n        self.assertEqual(m[0][0], 21)\n        self.assertEqual(m[0][4], 1)\n\nif __name__ == '__main__':\n    unittest.main()\n"
