          "solution": "def chain_rate(rates):\n    # Each hop multiplies onto the running rate; an empty path means\n    # \"same unit\", whose conversion factor is 1.0 (the identity).\n    product = 1.0\n    for r in rates:\n        product = product * r\n    return product\n",
          "tests": "import unittest\nfrom solution import chain_rate\n\n\nclass TestChainRate(unittest.TestCase):\n    def test_two_hops(self):\n        # a/b = 2.0, b/c = 3.0  ->  a/c = 6.0\n        self.assertEqual(chain_rate([2.0, 3.0]), 6.0)\n\n    def test_single_hop(self):\n        self.assertEqual(chain_rate([5.0]), 5.0)\n\n    def test_empty_is_identity(self):\n        # No hops at all: converting a unit to itself is factor 1.0.\n        self.assertEqual(chain_rate([]), 1.0)\n\n    def test_three_hops(self):\n        self.assertAlmostEqual(chain_rate([2.0, 0.5, 4.0]), 4.0)\n\n    def test_fractional(self):\n        self.assertAlmostEqual(chain_rate([0.1, 10.0]), 1.0)\n\n\nif __name__ == '__main__':\n    unittest.main()\n"
